-- =====================================================
-- Migration: 20260625000000_c02_retag_apply.sql
-- =====================================================
-- Description:
--   C02 — Cooking Skills & Main Ingredients re-tag APPLY (the metadata
--   rebuild's deferred "PR F"). Writes the reviewed, greenlit C02 re-tag output
--   to the live corpus for EXACTLY TWO metadata fields — cooking_skills and
--   main_ingredients — and NOTHING else. For every changing lesson it
--   dual-writes BOTH the lessons text[] column AND the matching camelCase
--   metadata JSONB key (cookingSkills / mainIngredients).
--
--   SHIP SOURCE (design §3·PIVOT D-P11): main_ingredients ships the deterministic
--   canonical floor only; cooking_skills ships floor-retention (floor ∪ the AI's
--   kept/added skills). Generated by scripts/stage2-retag/prepare-apply.ts over
--   the frozen Opus-4.8 full run (artifacts/c02-full-run.opus-4-8.jsonl), then
--   adapted here (the per-lesson UPDATE bodies are verbatim from that draft).
--
--   Compared lessons: 752; changing (snapshotted + updated): 450.
--
-- DATA SAFETY (design §3·PIVOT D-P10):
--   (a) C02-ONLY WRITE SCOPE — every UPDATE writes only cooking_skills +
--       main_ingredients (column + JSONB key). The other 15 metadata fields,
--       grade_levels, and academicConcepts are NEVER touched, so this apply can
--       never stomp the completed metadata rebuild.
--   (b) OPTIMISTIC CONCURRENCY GUARD — each UPDATE's WHERE also matches the row's
--       pre-apply (export-time) C02 arrays (order-insensitive mutual containment
--       + cardinality, NULL = empty set). A row a reviewer edited since the
--       corpus export no longer matches → it is SKIPPED (matches zero rows),
--       never stomped. Skipped rows are captured in public.c02_retag_skipped.
--   (c) C02-TARGETED ROLLBACK — the snapshot table public.c02_retag_rollback is
--       full-row (forensics), but the sibling *.sql.rollback restores ONLY the
--       two C02 columns + their two JSONB keys, so a restore never clobbers
--       unrelated post-apply edits to the other fields.
--   (d) DUAL-WRITE LOCKSTEP ASSERTION — section (4) hard-fails (rolls back the
--       whole migration) if, for any updated row, the text[] column and its
--       metadata JSONB key disagree on either C02 field.
--
--   NO CHECK CONSTRAINTS here (expand/contract, design §4 Q9): the
--   valid_cooking_skills / valid_main_ingredients CHECKs land in the SEPARATE
--   P4b migration, AFTER the closed frontend/Zod is deployed — a table-wide
--   CHECK can only follow canonicalization + a closed write surface.
--
-- Rollback: sibling 20260625000000_c02_retag_apply.sql.rollback (C02-targeted).
--
-- =====================================================
-- SECTIONS (LOAD-BEARING ORDER)
-- =====================================================
--   (1)  c02_retag_rollback DDL — full-row snapshot table (RLS on, NO policies).
--   (1b) Snapshot INSERT...SELECT...ON CONFLICT DO NOTHING — original values of
--        every changing row, captured BEFORE any UPDATE.
--   (1c) c02_retag_skipped capture — rows whose CURRENT C02 arrays drifted from
--        the export-time guard (a reviewer edited them since export). The
--        per-lesson UPDATEs carry the SAME guard, so these match zero rows there.
--   (2)  Per-lesson C02-only dual-write UPDATEs (absolute values; idempotent;
--        concurrency-guarded). 450 blocks.
--   (4)  Dual-write lockstep assertion (D-P10d, hard-fail).
--   (5)  ANALYZE public.lessons.

-- The whole apply runs in ONE explicit transaction: the Supabase CLI applies
-- statements in autocommit (extended protocol), so without this BEGIN/COMMIT a
-- bare LOCK (0) errors AND the section-(4) assertion could not atomically roll
-- back the data writes on failure. Wrapping gives both: the lock holds for the
-- whole apply, and a failed assertion aborts every UPDATE.
BEGIN;

-- =====================================================
-- (0) Serialize the apply against concurrent writes to public.lessons (GATE 2
--     Codex; design §3·PIVOT D-P10b hardening). Held for the migration's
--     (sub-second) transaction so the skip-capture (1c), the guarded UPDATEs
--     (2), and the lockstep assertion (4) all see ONE consistent snapshot of the
--     table. Without it, a reviewer edit committed between a row's skip-capture
--     and its guarded UPDATE could leave that row neither updated NOR recorded in
--     c02_retag_skipped — a "third state" the rollback would wrongly revert.
--     SHARE ROW EXCLUSIVE blocks concurrent INSERT/UPDATE/DELETE but still allows
--     SELECT reads; it is released at COMMIT. (Requires the runner's per-migration
--     transaction — the same property the section-(4) assertion relies on.)
-- =====================================================
LOCK TABLE public.lessons IN SHARE ROW EXCLUSIVE MODE;

-- =====================================================
-- (1) Rollback snapshot — original values of every changing row
-- =====================================================
CREATE TABLE IF NOT EXISTS public.c02_retag_rollback (
  lesson_id text PRIMARY KEY,
  activity_type text[],
  tags text[],
  season_timing text[],
  cultural_responsiveness_features text[],
  cultural_heritage text[],
  academic_integration text[],
  social_emotional_learning text[],
  core_competencies text[],
  cooking_methods text[],
  observances_holidays text[],
  garden_skills text[],
  cooking_skills text[],
  main_ingredients text[],
  grade_levels text[],
  metadata jsonb
);
-- Service-role-only: RLS enabled with NO policies.
ALTER TABLE public.c02_retag_rollback ENABLE ROW LEVEL SECURITY;

-- =====================================================
-- (1b) Snapshot the current values of every changing row
-- =====================================================
