-- =====================================================
-- (1c) Concurrency guard — capture rows skipped because a reviewer
--      edited their C02 tags since the corpus export (D-P10b).
--      The per-lesson UPDATEs below carry the SAME guard, so these
--      rows match zero rows there — they are skipped, NOT stomped.
-- =====================================================
CREATE TABLE IF NOT EXISTS public.c02_retag_skipped (
  lesson_id text PRIMARY KEY,
  current_cooking_skills text[],
  current_main_ingredients text[],
  expected_cooking_skills text[],
  expected_main_ingredients text[]
);
ALTER TABLE public.c02_retag_skipped ENABLE ROW LEVEL SECURITY;
INSERT INTO public.c02_retag_skipped (lesson_id, current_cooking_skills, current_main_ingredients, expected_cooking_skills, expected_main_ingredients)
SELECT l.lesson_id, l.cooking_skills, l.main_ingredients,
  ARRAY['Assembling cold dishes']::text[], ARRAY['Sprouts']::text[]
FROM public.lessons l
WHERE l.lesson_id = '0B-9rQRyZMNzUSkhwbDlBTmhsbGc'
  AND (NOT (coalesce(l.cooking_skills, '{}'::text[]) <@ ARRAY['Assembling cold dishes']::text[] AND coalesce(l.cooking_skills, '{}'::text[]) @> ARRAY['Assembling cold dishes']::text[] AND cardinality(coalesce(l.cooking_skills, '{}'::text[])) = cardinality(ARRAY['Assembling cold dishes']::text[])) OR NOT (coalesce(l.main_ingredients, '{}'::text[]) <@ ARRAY['Sprouts']::text[] AND coalesce(l.main_ingredients, '{}'::text[]) @> ARRAY['Sprouts']::text[] AND cardinality(coalesce(l.main_ingredients, '{}'::text[])) = cardinality(ARRAY['Sprouts']::text[])))
ON CONFLICT (lesson_id) DO NOTHING;
INSERT INTO public.c02_retag_skipped (lesson_id, current_cooking_skills, current_main_ingredients, expected_cooking_skills, expected_main_ingredients)
SELECT l.lesson_id, l.cooking_skills, l.main_ingredients,
  ARRAY['Assembling cold dishes']::text[], ARRAY['Berries']::text[]
FROM public.lessons l
WHERE l.lesson_id = '0B-9rQRyZMNzUZlFLYlc1Um1oZnM'
  AND (NOT (coalesce(l.cooking_skills, '{}'::text[]) <@ ARRAY['Assembling cold dishes']::text[] AND coalesce(l.cooking_skills, '{}'::text[]) @> ARRAY['Assembling cold dishes']::text[] AND cardinality(coalesce(l.cooking_skills, '{}'::text[])) = cardinality(ARRAY['Assembling cold dishes']::text[])) OR NOT (coalesce(l.main_ingredients, '{}'::text[]) <@ ARRAY['Berries']::text[] AND coalesce(l.main_ingredients, '{}'::text[]) @> ARRAY['Berries']::text[] AND cardinality(coalesce(l.main_ingredients, '{}'::text[])) = cardinality(ARRAY['Berries']::text[])))
ON CONFLICT (lesson_id) DO NOTHING;
INSERT INTO public.c02_retag_skipped (lesson_id, current_cooking_skills, current_main_ingredients, expected_cooking_skills, expected_main_ingredients)
SELECT l.lesson_id, l.cooking_skills, l.main_ingredients,
