-- =====================================================
-- (4) Dual-write lockstep assertion (design §3·PIVOT D-P10d, hard-fail)
-- =====================================================
-- Every UPDATE in (2) sets the text[] column AND its metadata JSONB key from the
-- SAME ordered literal in one atomic statement, so an UPDATED row is lockstep by
-- construction. This re-verifies it for defense-in-depth and ABORTS the whole
-- migration (RAISE EXCEPTION inside the migration's transaction) if any updated
-- row's column disagrees with its JSONB key on either C02 field.
--
-- Scope: rows in c02_retag_rollback (the changing set) MINUS c02_retag_skipped
-- (rows a reviewer edited since export → guard-skipped, NOT written by this
-- migration, so their pre-existing state must not fail the check). The remaining
-- rows are exactly the ones (2) wrote. Comparison is order-sensitive because both
-- sides come from the same ordered literal; a NULL column = '{}' (empty set).
DO $$
DECLARE
  mismatch_count integer;
BEGIN
  SELECT count(*) INTO mismatch_count
  FROM public.lessons l
  JOIN public.c02_retag_rollback r ON r.lesson_id = l.lesson_id
  WHERE NOT EXISTS (
          SELECT 1 FROM public.c02_retag_skipped s WHERE s.lesson_id = l.lesson_id
        )
    AND (
      coalesce(l.cooking_skills, '{}'::text[]) IS DISTINCT FROM
        coalesce(array(SELECT jsonb_array_elements_text(l.metadata -> 'cookingSkills')), '{}'::text[])
      OR
      coalesce(l.main_ingredients, '{}'::text[]) IS DISTINCT FROM
        coalesce(array(SELECT jsonb_array_elements_text(l.metadata -> 'mainIngredients')), '{}'::text[])
    );

  IF mismatch_count > 0 THEN
    RAISE EXCEPTION
      'C02 lockstep assertion FAILED: % updated row(s) have cooking_skills/main_ingredients column <> metadata JSONB key. Migration aborted.',
      mismatch_count;
  END IF;
END $$;

-- =====================================================
-- (5) Refresh planner stats after the bulk update.
-- =====================================================
ANALYZE public.lessons;

COMMIT;
